/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Features:
 * - HTML template rendering per notification type
 * - Recipient email validation
 * - Pluggable transport (swap EmailTransport for real provider)
 * - Retry support with configurable attempts
 * - Delivery tracking for observability
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailConfig {
  from: string;
  replyTo?: string;
  maxRetries?: number;
  appName?: string;
}

/**
 * A rendered email ready for transport.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  replyTo?: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface — swap this implementation for a real
 * email provider (SendGrid, SES, SMTP, etc.).
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores all sent emails for later inspection.
 */
export class InMemoryTransport implements EmailTransport {
  private inbox: Array<RenderedEmail & { messageId: string; sentAt: Date }> = [];

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    const messageId = `msg-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.inbox.push({ ...email, messageId, sentAt: new Date() });
    return { messageId };
  }

  getInbox(): Array<RenderedEmail & { messageId: string; sentAt: Date }> {
    return [...this.inbox];
  }

  clear(): void {
    this.inbox = [];
  }
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that a string looks like an email address.
 */
function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

/**
 * Resolve the recipient field from a NotificationPayload to an email address.
 *
 * The notification service may set recipient to either an email address
 * directly (e.g. from user.email) or a userId (e.g. from order.userId).
 * This function returns the value if it's already an email, or returns
 * null if it cannot be resolved (userId lookup would require a UserRepository
 * integration — callers should ensure payloads use email addresses).
 */
export function resolveRecipient(recipient: string): string | null {
  if (isValidEmail(recipient)) {
    return recipient;
  }
  return null;
}

/**
 * Render an HTML email body from a notification payload.
 * Uses simple string templates keyed by notification type (from metadata).
 */
export function renderTemplate(
  payload: NotificationPayload,
  appName: string,
): { html: string; text: string } {
  const notificationType = payload.metadata?.notificationType as NotificationType | undefined;

  const escapedSubject = escapeHtml(payload.subject);
  const escapedBody = escapeHtml(payload.body);
  const escapedAppName = escapeHtml(appName);

  const header = `<div style="background:#2563eb;color:#fff;padding:16px 24px;font-family:sans-serif;"><h2 style="margin:0;">${escapedAppName}</h2></div>`;
  const footer = `<div style="padding:16px 24px;color:#6b7280;font-size:12px;font-family:sans-serif;border-top:1px solid #e5e7eb;margin-top:24px;">This is an automated message from ${escapedAppName}. Please do not reply directly.</div>`;

  let contentHtml: string;

  switch (notificationType) {
    case 'order-confirmation': {
      const orderId = payload.metadata?.orderId ?? '';
      contentHtml = `
        <div style="padding:24px;font-family:sans-serif;">
          <h3 style="color:#1f2937;">Order Confirmed</h3>
          <p>Order <strong>${escapeHtml(String(orderId))}</strong> has been placed successfully.</p>
          <p>${escapedBody}</p>
        </div>`;
      break;
    }
    case 'order-status-update': {
      const orderId = payload.metadata?.orderId ?? '';
      const newStatus = payload.metadata?.newStatus ?? '';
      contentHtml = `
        <div style="padding:24px;font-family:sans-serif;">
          <h3 style="color:#1f2937;">Order Status Update</h3>
          <p>Order <strong>${escapeHtml(String(orderId))}</strong> is now <strong>${escapeHtml(String(newStatus))}</strong>.</p>
          <p>${escapedBody}</p>
        </div>`;
      break;
    }
    case 'user-welcome': {
      contentHtml = `
        <div style="padding:24px;font-family:sans-serif;">
          <h3 style="color:#1f2937;">Welcome!</h3>
          <p>${escapedBody}</p>
          <p>We're glad to have you on board.</p>
        </div>`;
      break;
    }
    default: {
      contentHtml = `
        <div style="padding:24px;font-family:sans-serif;">
          <h3 style="color:#1f2937;">${escapedSubject}</h3>
          <p>${escapedBody}</p>
        </div>`;
    }
  }

  const html = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f3f4f6;">${header}${contentHtml}${footer}</body></html>`;
  const text = `${payload.subject}\n\n${payload.body}\n\n--\n${appName}`;

  return { html, text };
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private config: Required<Pick<EmailConfig, 'from' | 'maxRetries' | 'appName'>> & Pick<EmailConfig, 'replyTo'>;

  constructor(config: EmailConfig, transport?: EmailTransport) {
    this.config = {
      from: config.from,
      replyTo: config.replyTo,
      maxRetries: config.maxRetries ?? 2,
      appName: config.appName ?? 'TaskFlow Pro',
    };
    this.transport = transport ?? new InMemoryTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const recipient = resolveRecipient(payload.recipient);
    if (!recipient) {
      this.logger.warn(`Invalid or unresolvable recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: `email-${Date.now()}`,
        channel: 'email',
        error: `Invalid recipient email: ${payload.recipient}`,
      };
    }

    const { html, text } = renderTemplate(payload, this.config.appName);

    const renderedEmail: RenderedEmail = {
      to: recipient,
      from: this.config.from,
      replyTo: this.config.replyTo,
      subject: payload.subject,
      html,
      text,
    };

    let lastError: unknown;
    const maxAttempts = this.config.maxRetries + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const result = await this.transport.sendMail(renderedEmail);
        this.logger.info(
          `Email sent to ${recipient}: "${payload.subject}" (messageId: ${result.messageId})`,
        );
        return {
          success: true,
          notificationId: result.messageId,
          channel: 'email',
        };
      } catch (error) {
        lastError = error;
        this.logger.warn(
          `Email send attempt ${attempt}/${maxAttempts} failed for ${recipient}: ${error}`,
        );
      }
    }

    const errorMsg = lastError instanceof Error ? lastError.message : String(lastError);
    this.logger.error(`Email delivery failed after ${maxAttempts} attempts to ${recipient}: ${errorMsg}`);
    return {
      success: false,
      notificationId: `email-failed-${Date.now()}`,
      channel: 'email',
      error: `Delivery failed after ${maxAttempts} attempts: ${errorMsg}`,
    };
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  renderTemplate,
  resolveRecipient,
} from '../../src/adapters/email.adapter.js';
import type {
