function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    channel: 'email',
    priority: 'normal',
    ...overrides,
  };
}

describe('resolveRecipient', () => {
  it('should return valid email addresses as-is', () => {
    expect(resolveRecipient('alice@example.com')).toBe('alice@example.com');
    expect(resolveRecipient('user+tag@sub.domain.org')).toBe('user+tag@sub.domain.org');
  });

  it('should return null for non-email strings', () => {
    expect(resolveRecipient('user-123')).toBeNull();
    expect(resolveRecipient('')).toBeNull();
    expect(resolveRecipient('not an email')).toBeNull();
  });
});

describe('renderTemplate', () => {
  it('should render default template when no notificationType metadata', () => {
    const payload = makePayload();
    const { html, text } = renderTemplate(payload, 'TaskFlow Pro');

    expect(html).toContain('Test Subject');
    expect(html).toContain('Test body content');
    expect(html).toContain('TaskFlow Pro');
    expect(text).toContain('Test Subject');
    expect(text).toContain('Test body content');
  });

  it('should render order-confirmation template', () => {
    const payload = makePayload({
      subject: 'Order Confirmation: order-1',
      body: 'Items: Widget x2. Total: $20.00',
      metadata: { notificationType: 'order-confirmation', orderId: 'order-1' },
    });
    const { html } = renderTemplate(payload, 'TaskFlow Pro');

    expect(html).toContain('Order Confirmed');
    expect(html).toContain('order-1');
    expect(html).toContain('Widget x2');
  });

  it('should render order-status-update template', () => {
    const payload = makePayload({
      subject: 'Order Update: order-1',
      body: 'Your order status has changed from pending to confirmed.',
      metadata: { notificationType: 'order-status-update', orderId: 'order-1', newStatus: 'confirmed' },
    });
    const { html } = renderTemplate(payload, 'TaskFlow Pro');

    expect(html).toContain('Order Status Update');
    expect(html).toContain('confirmed');
  });

  it('should render user-welcome template', () => {
    const payload = makePayload({
      subject: 'Welcome to TaskFlow Pro',
      body: 'Hi Alice, welcome to TaskFlow Pro!',
      metadata: { notificationType: 'user-welcome' },
    });
    const { html } = renderTemplate(payload, 'TaskFlow Pro');

    expect(html).toContain('Welcome!');
    expect(html).toContain('glad to have you');
  });

