    });
    const { html } = renderTemplate(payload, 'TestApp');

    expect(html).not.toContain('<script>');
    expect(html).not.toContain('<img onerror');
    expect(html).toContain('&lt;script&gt;');
  });
});

describe('InMemoryTransport', () => {
