describe('EmailAdapter', () => {
  let transport: InMemoryTransport;
  let adapter: EmailAdapter;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter(
      { from: 'noreply@taskflow.com', replyTo: 'support@taskflow.com', appName: 'TaskFlow Pro' },
      transport,
    );
  });

  it('should have channel set to email', () => {
    expect(adapter.channel).toBe('email');
  });

  it('should send an email successfully', async () => {
    const payload = makePayload();
    const result = await adapter.send(payload);

    expect(result.success).toBe(true);
    expect(result.channel).toBe('email');
    expect(result.notificationId).toBeTruthy();

    const inbox = transport.getInbox();
    expect(inbox).toHaveLength(1);
    expect(inbox[0]?.to).toBe('alice@example.com');
    expect(inbox[0]?.from).toBe('noreply@taskflow.com');
    expect(inbox[0]?.replyTo).toBe('support@taskflow.com');
    expect(inbox[0]?.subject).toBe('Test Subject');
    expect(inbox[0]?.html).toContain('Test body content');
    expect(inbox[0]?.text).toContain('Test body content');
  });

  it('should fail for invalid recipient email', async () => {
    const payload = makePayload({ recipient: 'not-an-email' });
    const result = await adapter.send(payload);

    expect(result.success).toBe(false);
    expect(result.error).toContain('Invalid recipient email');
    expect(transport.getInbox()).toHaveLength(0);
  });

  it('should retry on transport failure and eventually fail', async () => {
    const failingTransport: EmailTransport = {
      sendMail: vi.fn().mockRejectedValue(new Error('SMTP connection refused')),
    };
    const retryAdapter = new EmailAdapter(
      { from: 'noreply@taskflow.com', maxRetries: 2 },
      failingTransport,
    );

    const result = await retryAdapter.send(makePayload());

    expect(result.success).toBe(false);
    expect(result.error).toContain('Delivery failed after 3 attempts');
    expect(result.error).toContain('SMTP connection refused');
    expect(failingTransport.sendMail).toHaveBeenCalledTimes(3);
  });

  it('should succeed on retry after initial failure', async () => {
    let callCount = 0;
    const flakyTransport: EmailTransport = {
      sendMail: vi.fn().mockImplementation(async () => {
        callCount++;
        if (callCount === 1) {
          throw new Error('Temporary failure');
        }
        return { messageId: 'msg-retry-success' };
      }),
    };
    const retryAdapter = new EmailAdapter(
      { from: 'noreply@taskflow.com', maxRetries: 2 },
      flakyTransport,
    );

    const result = await retryAdapter.send(makePayload());

    expect(result.success).toBe(true);
    expect(result.notificationId).toBe('msg-retry-success');
    expect(flakyTransport.sendMail).toHaveBeenCalledTimes(2);
  });

  it('should use InMemoryTransport by default', () => {
    const defaultAdapter = new EmailAdapter({ from: 'test@test.com' });
    expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryTransport);
  });

  it('should render HTML template in sent email', async () => {
    const payload = makePayload({
      subject: 'Order Confirmation: order-42',
      body: 'Items: Gadget x1. Total: $25.00',
      metadata: { notificationType: 'order-confirmation', orderId: 'order-42' },
    });

    await adapter.send(payload);

    const inbox = transport.getInbox();
    expect(inbox[0]?.html).toContain('Order Confirmed');
    expect(inbox[0]?.html).toContain('order-42');
    expect(inbox[0]?.html).toContain('TaskFlow Pro');
  });
});

